// Eingabe-Pipeline für Carol-Gray-Social-Stories.
//
// Liest die vier Webhook-Felder (Titel, Situation, Verhaltensziel, Altersgruppe)
// und bereitet alles vor, was die downstream Nodes brauchen:
//  - slug (deterministisch hashbasiert, gleiche Eingabe -> gleiche Datei)
//  - imageStylePositive/Negative (fest „Traumwelt", einziger Bildstil)
//  - imageCount = 5 (Hero-Bild + 4 Inline-Bilder zwischen den Absätzen)
//  - description (kurze Variante der Situation für SEO-Meta-Tag)
//  - userPrompt (Variablen-Block für den Carol-Gray-Autor-LLM-Node)
//
// Alle Lesekumpel-Konzepte (Persona, Neurotyp, Bildstil-Auswahl, mitBildern,
// Persona-Meta-Map mit Wortzahlen/Tempus/Avataren) sind entfernt — der Workflow
// produziert ausschließlich Carol-Gray-Social-Stories.

const webhookInput = $('Webhook: Geschichte anfordern').first().json;
const input = webhookInput.body || webhookInput;

const title = (input['Titel'] || '').trim();
const situation = (input['Situation'] || '').trim();
const verhaltensziel = (input['Verhaltensziel'] || '').trim();
const altersgruppeRaw = (input['Altersgruppe'] || 'allgemein').trim().toLowerCase();

const ALLOWED_ALTERSGRUPPEN = ['vorschule', 'grundschule', 'teenager', 'junge-erwachsene', 'erwachsene'];
const altersgruppe = ALLOWED_ALTERSGRUPPEN.includes(altersgruppeRaw) ? altersgruppeRaw : 'allgemein';

// Slug — deterministisch via DJB2-Hash. Gleicher Titel + Situation + Altersgruppe
// -> gleicher Slug -> gleiche Dateipfade (Idempotenz bei Caller-Retry).
const umlautMap = { 'ä': 'ae', 'ö': 'oe', 'ü': 'ue', 'ß': 'ss', 'Ä': 'ae', 'Ö': 'oe', 'Ü': 'ue' };
const slugBase = (title.toLowerCase()
  .replace(/[äöüßÄÖÜ]/g, c => umlautMap[c] || c)
  .replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '').replace(/-+/g, '-')
  .substring(0, 55) || 'neue-geschichte');
const slugInput = title + '|' + situation + '|' + altersgruppe;
let _h = 5381;
for (let i = 0; i < slugInput.length; i++) { _h = ((_h * 33) ^ slugInput.charCodeAt(i)) | 0; }
const slugSuffix = ((_h >>> 0).toString(36) + '0000').substring(0, 4);
const slug = slugBase + '-' + slugSuffix;

// Bildstil ist fest „Aquarell" — warmes, kinderbuchartiges Handgemalt-Gefühl
// (Beatrix Potter / Quentin Blake). Sorgt für visuelle Konsistenz über alle
// Stories. Frühere Wahl „Traumwelt" produzierte mit ihren großen Anime-Augen
// und kühlem Rim-Light teils distanziert/melancholisch wirkende Gesichter.
const imageStylePositive = "traditional children's book watercolor illustration, hand-painted with warm cream paper texture filling the entire image, soft pastel palette, gentle wet-on-wet washes with visible bleeding edges, loose expressive brush strokes, soft painterly rendering, warm friendly facial expressions, inspired by Beatrix Potter and Quentin Blake, consistent palette and brush handling across all panels of this story, same character proportions and facial features in every panel, full bleed composition extending to all four image edges, no inner framing, subjects and background reach every corner of the image, square 1:1 aspect ratio";
const imageStyleNegative = "no text, no watermarks, no labels, no tags, no annotations, no nameplates, no UI overlays, no callouts, no captions, no speech bubbles, no sign text, no alphanumeric text in image, no letterboxing, no black bars, no white margin, no cream margin, no paper border, no inner matte, no mat board, no illustration frame, no vignette, no aspect-ratio padding, no hard black outlines, no digital vector look, no CGI, no 3D shading, no photorealism, no extra limbs, no duplicate props, no floating objects, no mixed art styles, no style drift, no oversized anime eyes, no rim lighting, no eerie atmosphere, no melancholic faces";

const imageCount = 5;

// Alter & Geschlecht der Hauptfigur ("Ich") für die Bildgenerierung deterministisch
// festlegen. Ohne diese explizite Vorgabe interpretiert der Story-Elemente-Extraktor
// das Alter aus dem Story-Text-Kontext (oft falsch: alle Stories landeten bei 8 J.)
// und wählt das Geschlecht aus seinem Trainingsbias (fast immer männlich).
//
// Alter pro Altersgruppe (Mitte des Bereichs):
const AGE_MAP = {
  'vorschule': 5,
  'grundschule': 9,
  'teenager': 15,
  'junge-erwachsene': 23,
  'erwachsene': 38,
  'allgemein': 9
};
const mainCharacterAge = AGE_MAP[altersgruppe] || 9;

// Geschlecht: optional per Webhook-Feld "Hauptfigur" überschreibbar, sonst
// deterministische Rotation über alle 3 Gender, basierend auf Slug-Hash.
const hauptfigurInput = (input['Hauptfigur'] || '').toString().trim().toLowerCase();
let mainCharacterGender;
if (/m[aä]dchen|frau|weibl/.test(hauptfigurInput))                mainCharacterGender = 'female';
else if (/junge|mann|männl|maennl/.test(hauptfigurInput))         mainCharacterGender = 'male';
else if (/nicht.?binär|nicht.?binaer|non.?binary|nb/.test(hauptfigurInput)) mainCharacterGender = 'non-binary';
else {
  const GENDERS = ['female', 'male', 'non-binary'];
  mainCharacterGender = GENDERS[Math.abs(_h) % GENDERS.length];
}

// SEO-Beschreibung: erste 140 Zeichen der Situation, an Wortgrenze geschnitten.
function shortDesc(text, maxLen) {
  const s = String(text || '').replace(/\s+/g, ' ').trim();
  if (s.length <= maxLen) return s;
  const cut = s.substring(0, maxLen);
  const lastSpace = cut.lastIndexOf(' ');
  return (lastSpace > maxLen * 0.6 ? cut.substring(0, lastSpace) : cut).trimEnd() + '…';
}
const description = shortDesc(situation, 140);

// User-Prompt für den Carol-Gray-Autor-LLM. Der System-Prompt (siehe
// n8n-pipeline/prompts/carol-gray-autor.md) liefert die Methodik-Regeln;
// hier kommen nur die situationsspezifischen Variablen rein.
const userPrompt = [
  `Titel: "${title}"`,
  '',
  `Situation: ${situation}`,
  '',
  `Verhaltensziel: ${verhaltensziel}`,
  '',
  `Altersgruppe: ${altersgruppe}`,
  '',
  'Schreibe jetzt die Social Story:',
  '- 200 bis 300 Wörter insgesamt',
  '- genau 6 Absätze, jeweils durch eine Leerzeile getrennt',
  '- Ich-Perspektive, Präsens',
  '- max. 1 bis 2 DIREKTIV-Sätze in der ganzen Geschichte',
  '- folge dem Story-Bogen aus deinem System-Prompt'
].join('\n');

const today = new Date().toISOString().slice(0, 10);

return {
  json: {
    title,
    situation,
    verhaltensziel,
    altersgruppe,
    slug,
    imageCount,
    imageStylePositive,
    imageStyleNegative,
    description,
    userPrompt,
    mainCharacterAge,
    mainCharacterGender,
    date: today
  }
};

const input = $('Daten vorbereiten').first().json;
const responseText = $input.item.json.text || $input.item.json.output || '';

// Tolerant label matcher — accepts Markdown markers (# ## ### ** **), with or without colon,
// with or without German hyphenation (GE-SCHICH-TE, ZU-SAM-MEN-FAS-SUNG).
// Returns both the label-START position (cuts previous section) and label-END position (content start).
function findLabelPositions(text, labelPattern) {
  const re = new RegExp("(?:#{1,3}\\s*|\\*\\*\\s*)?" + labelPattern + "(?::|\\s)\\s*\\*?\\*?", "i");
  const m = text.match(re);
  if (!m) return null;
  return { start: m.index, end: m.index + m[0].length };
}
const geschPattern = "GE\\s*-?\\s*SCHICH\\s*-?\\s*TE";
const zusamPattern = "ZU\\s*-?\\s*SAM\\s*-?\\s*MEN\\s*-?\\s*FAS\\s*-?\\s*SUNG";
const gesch = findLabelPositions(responseText, geschPattern);
const zusam = findLabelPositions(responseText, zusamPattern);

let rawStory, summaryText;
if (gesch && zusam && zusam.start > gesch.end) {
  rawStory = responseText.substring(gesch.end, zusam.start).trim();
  summaryText = responseText.substring(zusam.end).trim();
} else if (gesch) {
  rawStory = responseText.substring(gesch.end).trim();
  summaryText = '';
} else {
  rawStory = responseText.trim();
  summaryText = '';
}

// Strip residual Markdown from both blocks (LLM may sometimes emit # or ** despite instructions)
function cleanMarkdown(s) {
  return s
    .replace(/^[#*]+\s*/gm, '')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .trim();
}
rawStory = cleanMarkdown(rawStory);
summaryText = cleanMarkdown(summaryText) || rawStory.split('\n')[0];

// ═══════════════════════════════════════════════════
// Deutsche Silbentrennung v2 (Digraphen-aware)
// ═══════════════════════════════════════════════════

function silbentrennung(wort) {
  if (wort.length <= 3) return wort;
  if (!/^[a-zäöüß]+$/i.test(wort)) return wort;

  const w = wort.toLowerCase();

  // Schritt 1: Wort in Einheiten zerlegen (Digraphen als eine Einheit)
  const einheiten = [];
  let i = 0;
  while (i < w.length) {
    // Trigraph: sch
    if (i + 2 < w.length && w.substring(i, i + 3) === 'sch') {
      einheiten.push({ text: w.substring(i, i + 3), typ: 'K', pos: i, len: 3 });
      i += 3; continue;
    }
    // Digraphen: ch, ck, ph, th, qu, pf, ng, nk
    const zwei = i + 1 < w.length ? w.substring(i, i + 2) : '';
    if (['ch', 'ck', 'ph', 'th', 'qu', 'pf'].includes(zwei)) {
      einheiten.push({ text: zwei, typ: 'K', pos: i, len: 2 });
      i += 2; continue;
    }
    // Doppelvokale: ei, au, eu, äu, ie, ai
    if (['ei', 'au', 'eu', 'äu', 'ie', 'ai'].includes(zwei)) {
      einheiten.push({ text: zwei, typ: 'V', pos: i, len: 2 });
      i += 2; continue;
    }
    // Einzelbuchstabe
    const vokal = 'aeiouyäöü'.includes(w[i]);
    einheiten.push({ text: w[i], typ: vokal ? 'V' : 'K', pos: i, len: 1 });
    i++;
  }

  // Schritt 2: Vokalgruppen finden (aufeinanderfolgende V-Einheiten)
  const vokalIndices = [];
  for (let e = 0; e < einheiten.length; e++) {
    if (einheiten[e].typ === 'V') {
      // Gehört zur vorherigen Vokalgruppe?
      if (vokalIndices.length > 0 && vokalIndices[vokalIndices.length - 1].end === e) {
        vokalIndices[vokalIndices.length - 1].end = e + 1;
      } else {
        vokalIndices.push({ start: e, end: e + 1 });
      }
    }
  }

  if (vokalIndices.length < 2) return wort;

  // Schritt 3: Trennstellen zwischen Vokalgruppen
  const trennstellen = [];
  for (let v = 0; v < vokalIndices.length - 1; v++) {
    const nachVokal = vokalIndices[v].end;       // erste Konsonant-Einheit nach Vokal
    const vorVokal = vokalIndices[v + 1].start;  // erste Vokal-Einheit der nächsten Silbe
    const anzahlKons = vorVokal - nachVokal;

    let trennEinheit;
    if (anzahlKons === 0) {
      // Vokal-Vokal: trenne dazwischen
      trennEinheit = nachVokal;
    } else if (anzahlKons === 1) {
      // 1 Konsonant(engruppe): gehört zur nächsten Silbe
      trennEinheit = nachVokal;
    } else {
      // 2+ Konsonanten: letzter Konsonant (oder letzte Digraph-Einheit) zur nächsten Silbe
      trennEinheit = vorVokal - 1;

      // st bleibt zusammen (st gehört zur nächsten Silbe)
      if (anzahlKons >= 2) {
        const vorletzte = einheiten[vorVokal - 2];
        const letzte = einheiten[vorVokal - 1];
        if (vorletzte.text === 's' && letzte.text === 't') {
          trennEinheit = vorVokal - 2;
        }
      }
    }

    // Position im Original-Wort
    const charPos = einheiten[trennEinheit].pos;
    if (charPos > 0 && charPos < wort.length) {
      trennstellen.push(charPos);
    }
  }

  // Schritt 4: Wort zusammenbauen
  if (trennstellen.length === 0) return wort;

  let ergebnis = '';
  let letzte = 0;
  for (const pos of trennstellen) {
    ergebnis += wort.substring(letzte, pos) + '-';
    letzte = pos;
  }
  ergebnis += wort.substring(letzte);

  return ergebnis;
}

function textSilbentrennung(text) {
  return text.replace(/[a-zäöüßA-ZÄÖÜ]{4,}/g, (wort) => silbentrennung(wort));
}

const storyText = textSilbentrennung(rawStory);
const wordCount = rawStory.split(/\s+/).length;

return { json: { ...input, storyText, rawStoryText: rawStory, summaryText, wordCount } };

const prevData = $('Bildszenen vorbereiten').first().json;
if (prevData.skipImages || prevData.imageCount === 0) {
  return [{ json: { ...prevData, _skipLoop: true } }];
}

const prev = $('Bildszenen vorbereiten').first().json;
const rawText = $input.first().json.text || '';
const visualLock = prev.visualLock || prev.characterReference || '';

// Lead-Block: erzwingt full-bleed-Komposition am Promptanfang (Modelle gewichten Anfang stärker)
const fullBleedMandate = [
  'FULL-BLEED MANDATE: This is a poster-style full-bleed illustration.',
  'The painted scene fills 100% of pixels from corner to corner of the image.',
  'Background paint and scene elements extend BEYOND all four image edges.',
  'There is no border, no margin, no white space, no matte, no frame, no rounded corners.',
  'Imagine a giant poster cropped tight to the artwork — every pixel is painted scene.'
].join(' ');

// safetyContext bleibt type-aware (Mensch+Tier-Kombination braucht andere Clothing-Klausel)
const _hasNonHuman = !!prev.hasNonHumanCharacter;
const _clothingClause = _hasNonHuman
  ? 'human characters are fully clothed in everyday outfits, animal characters are real animals with no clothing and no costume'
  : 'fully clothed characters in everyday outfits';
const safetyContext = "Wholesome G-rated illustration for a published German children's picture book, age-appropriate storybook art, " + _clothingClause;
const safetyNegative = 'no swimwear, no swimsuit, no bikini, no underwear, no nudity, no bare torso, no exposed skin beyond face and hands, no animals depicted as humans, no children wearing animal costumes';

// Frame-Bias-Negationen (zusätzlich zum imageStyleNegative)
const frameNegative = 'no canvas border, no torn paper edge, no rounded corners, no shadow box, no drop shadow around image, no decorative frame, no book page edge, no album cover frame, no inset background, no centered medallion composition, no white halo around subject';

const imageStylePositive = prev.imageStylePositive || "children's book illustration, consistent rendering across all panels";
const imageStyleNegative = prev.imageStyleNegative || "no text, no watermarks, no extra limbs";

let scenes = [];
try { const m = rawText.match(/\[[\s\S]*\]/); if (m) scenes = JSON.parse(m[0]); } catch(e) {}

if (!Array.isArray(scenes) || scenes.length === 0) {
  // Fallback: single generic scene
  scenes = [{
    scene: 1,
    momentSummary: 'A friendly scene from the story',
    action: 'standing',
    pose: 'natural relaxed pose',
    camera: 'eye-level medium shot',
    characters_present: [],
    props_shown: [],
    setting_focus: '',
    mood: 'warm'
  }];
}

function clean(s) { return (s == null ? '' : String(s)).trim(); }
function has(s) { return clean(s).length > 0; }

return scenes.map(s => {
  const sceneNo  = (typeof s.scene === 'number' && s.scene > 0) ? s.scene : 1;
  const summary  = clean(s.momentSummary) || 'A moment from the story';
  const action   = clean(s.action) || 'standing';
  const pose     = clean(s.pose)   || 'natural relaxed pose';
  const camera   = clean(s.camera) || 'eye-level medium shot';
  const chars    = Array.isArray(s.characters_present) ? s.characters_present.filter(has) : [];
  const props    = Array.isArray(s.props_shown) ? s.props_shown.filter(p => p && has(p.name)) : [];
  const setFocus = clean(s.setting_focus);
  const mood     = clean(s.mood) || 'warm';

  const propsLine = props.length > 0
    ? props.map(p => `${clean(p.name)} (${clean(p.hand) || 'in hand'})`).join(', ')
    : 'no held props this scene';
  const charsLine = chars.length > 0 ? chars.join(', ') : 'characters from VISUAL LOCK';

  const sceneBlock = [
    `SCENE ${sceneNo}: ${summary}`,
    `  Action:        ${action}`,
    `  Pose:          ${pose}`,
    `  Camera:        ${camera}`,
    `  In frame:      ${charsLine}`,
    `  Props shown:   ${propsLine}`,
    setFocus ? `  Setting focus: ${setFocus}` : '',
    `  Mood:          ${mood}`
  ].filter(Boolean).join('\n');

  // Finaler Prompt: FULL-BLEED Lead → safetyContext → VISUAL LOCK → SCENE → STYLE → NEGATIVE
  const positiveSections = [
    fullBleedMandate,
    safetyContext + '.',
    visualLock,
    sceneBlock,
    'ART STYLE: ' + imageStylePositive
  ].filter(Boolean);
  const positive = positiveSections.join('\n\n');

  const fullNegative = [imageStyleNegative, safetyNegative, frameNegative].filter(has).join(', ');
  const finalPrompt  = positive + '\n\n| NEGATIVE: ' + fullNegative;

  // paragraphIndex vom AI-Output durchreichen — wird im HTML-Assembler genutzt,
  // um Bilder zwischen den richtigen Absätzen zu platzieren.
  const paragraphIndex = (typeof s.paragraphIndex === 'number' && s.paragraphIndex >= 1) ? s.paragraphIndex : null;

  return {
    json: {
      ...prev,
      sceneIndex: sceneNo,
      paragraphIndex,
      imagePrompt: finalPrompt,
      imageFilename: prev.slug + '-' + sceneNo + '.png',
      imageGithubPath: 'social-stories/bilder/' + prev.slug + '-' + sceneNo + '.png',
      geminiRequestBody: {
        contents: [{ role: 'user', parts: [{ text: finalPrompt }] }],
        generationConfig: { responseModalities: ['image', 'text'] }
      }
    }
  };
});

// HTML-Assembler für SHG Social-Stories.
// Baut aus Story-Text + Bild-Positionen ein fertiges Article-HTML zusammen,
// das vom n8n-Workflow ins SHG-Repo gepusht wird (social-stories/<altersgruppe>/<slug>.html).
// Lesekumpel-spezifische Features (Quiz, Schatzsuche, Weitererzählen, Wortschatz,
// Persona-Avatar, Emoji-Versionen) sind im neuen SHG-Template nicht mehr enthalten
// und werden hier deshalb ignoriert, selbst wenn die vorgeschalteten Workflow-Nodes
// sie noch liefern.

const data = $('Geschichte parsen').first().json;
let template = $input.item.json.data;

const SITE_BASE = 'https://www.ass-elternkreis-nwm.de';
const altersgruppe = (data.altersgruppe || 'allgemein').toString().trim().toLowerCase();
const slug = (data.slug || 'neue-geschichte').toString();
const storyPath = `social-stories/${altersgruppe}/${slug}.html`;
const today = new Date().toISOString().slice(0, 10);
const storyDate = (data.date || today).toString().slice(0, 10);

function htmlEscape(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;').replace(/"/g, '&quot;')
    .replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

// SEO-Beschreibung: aus description, ohne Lesekumpel-Präfixe.
const descRaw = (data.description || data.title || '').toString().trim();
const metaDescription = descRaw.length > 157 ? descRaw.substring(0, 157).trimEnd() + '…' : descRaw;
const metaKeywords = ['Soziale Geschichte', 'Autismus', 'ASS', 'Carol Gray', data.genre, data.title]
  .filter(Boolean).join(', ');

// Hero = scene 1. Inline-Bilder ab scene 2 (verhindert Doppelung).
const heroImageUrl = `${SITE_BASE}/social-stories/bilder/${slug}-1.png`;
const imageCount = Number(data.imageCount || 0);

// imagePositions baue ich aus den Szenen-Items zusammen — jedes Szene-Item kommt
// aus 'Szenen parsen' und enthält sceneIndex + paragraphIndex (sofern AI ihn lieferte).
// paragraphIndex ist 0-basiert; per Konvention >= 1 (Story beginnt immer mit Prosa).
// Bild scene 1 ist als geblurrtes Hero-Bild ZUSÄTZLICH oben — die klare Inline-Version
// folgt unten an der vom AI gewählten paragraphIndex-Position.
const positionsByParagraph = new Map();
try {
  const sceneItems = $('Szenen parsen').all() || [];
  for (const item of sceneItems) {
    const j = item.json || {};
    const scene = j.sceneIndex;
    const pIdx = j.paragraphIndex;
    if (typeof scene === 'number' && scene >= 1 && scene <= imageCount &&
        typeof pIdx === 'number' && pIdx >= 1) {
      positionsByParagraph.set(pIdx, scene);
    }
  }
} catch (e) { /* fallback regelt das */ }

// Silbentrennung entfernen: Sicherheitsnetz, falls die LLM trotz Prompt-Verbot
// doch Häppchen-Trennung produziert (Lesekumpel-Erbe im Gemini-Trainingskontext).
function removeHyphenation(s) {
  const pat = /([a-zäöüßA-ZÄÖÜ])-([a-zäöüß])/g;
  let prev;
  do { prev = s; s = s.replace(pat, '$1$2'); } while (prev !== s);
  return s;
}
const paragraphs = (data.storyText || '').toString().split(/\n\n+/)
  .map(p => removeHyphenation(p.trim()))
  .filter(Boolean);
let storyHtml = '';
for (let i = 0; i < paragraphs.length; i++) {
  if (positionsByParagraph.has(i)) {
    const scene = positionsByParagraph.get(i);
    const imgUrl = `${SITE_BASE}/social-stories/bilder/${slug}-${scene}.png`;
    storyHtml += `          <img src="${imgUrl}" alt="${htmlEscape(data.title)} – Bild ${scene}" loading="lazy">\n`;
  }
  storyHtml += `          <p>${htmlEscape(paragraphs[i])}</p>\n`;
}
// Falls keine Position-Mappings vorhanden: alle Bilder ab scene 1 ans Ende, damit nichts verloren geht.
if (positionsByParagraph.size === 0 && imageCount >= 1) {
  for (let scene = 1; scene <= imageCount; scene++) {
    const imgUrl = `${SITE_BASE}/social-stories/bilder/${slug}-${scene}.png`;
    storyHtml += `          <img src="${imgUrl}" alt="${htmlEscape(data.title)} – Bild ${scene}" loading="lazy">\n`;
  }
}

template = template
  .replace(/\{\{STORY_TITLE\}\}/g, htmlEscape(data.title || ''))
  .replace(/\{\{STORY_HTML\}\}/g, storyHtml.trimEnd())
  .replace(/\{\{HERO_IMAGE_URL\}\}/g, heroImageUrl)
  .replace(/\{\{META_DESCRIPTION\}\}/g, htmlEscape(metaDescription))
  .replace(/\{\{META_KEYWORDS\}\}/g, htmlEscape(metaKeywords))
  .replace(/\{\{STORY_PATH\}\}/g, storyPath)
  .replace(/\{\{STORY_DATE\}\}/g, htmlEscape(storyDate))
  .replace(/\{\{SLUG\}\}/g, slug);

// Safety-Net: verbliebene Platzhalter loggen und auf '' stripen
const residuals = template.match(/\{\{[A-Z_]+\}\}/g);
if (residuals) {
  const unique = [...new Set(residuals)];
  console.warn('HTML assemblieren: unresolved placeholders ->', unique.join(', '));
  template = template.replace(/\{\{[A-Z_]+\}\}/g, '');
}

const htmlBase64 = Buffer.from(template, 'utf8').toString('base64');
const storyUrl = `${SITE_BASE}/${storyPath}`;

return {
  json: {
    ...data,
    htmlBase64,
    filePath: storyPath,
    commitMessage: `Social Story: ${data.title || slug}`,
    storyUrl
  }
};

const prev = $('Story-Elemente vorbereiten').first().json;
const rawText = $input.first().json.text || '';

let storyElements = { characters: [], props: [], setting: '', sceneRules: [] };
try {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) storyElements = JSON.parse(m[0]);
} catch(e) {}

if (!Array.isArray(storyElements.sceneRules)) storyElements.sceneRules = [];
if (!Array.isArray(storyElements.characters)) storyElements.characters = [];
if (!Array.isArray(storyElements.props))      storyElements.props      = [];

const clothingRegex = new RegExp("\\b(wearing|shirt|dress|trousers|pants|shorts|jacket|hoodie|coat|sweater|skirt|outfit|clothes|kleidung)\\b", "i");

function clean(s) {
  return (s == null ? '' : String(s)).trim();
}
function has(s) { return clean(s).length > 0 && clean(s).toLowerCase() !== 'null'; }

function indent2(s) {
  return clean(s).split('\n').map(l => '    ' + l).join('\n');
}

function filterVisualOnlyDF(arr) {
  // Filtert Eintraege heraus, die Verhalten/Biologie statt visueller Merkmale beschreiben.
  // Verhaltens-Eintraege ("One eye remains open while sleeping") werden vom Bildmodell
  // visuell umgesetzt und produzieren Uncanny-Valley-Artefakte.
  const BEHAVIOR_RE = /\b(while|when|during|whenever|always|sometimes|remains?|stays?|becomes?|sleeps?|sleeping|asleep|dreams?|dreaming|swims?|swimming|flies|flying|flew|walking|running|jumping|jumps?|dancing|dances?|sings?|singing|breathes?|breathing|breath|observes?|observing|watches?|watching|listens?|listening|hunts?|hunting|hides?|hiding|eats?|eating|drinks?|drinking|rests?|resting|awake|alert|active|asleep|half\s*of\s*its\s*brain|brain\s*rests)\b/i;
  return (arr || []).filter(s => {
    const t = String(s || '').trim();
    if (!t) return false;
    if (BEHAVIOR_RE.test(t)) return false;
    return true;
  });
}

function buildHumanBlock(c, idx) {
  const lines = [];
  const name  = clean(c.name) || ('Character #' + idx);
  const age   = (typeof c.ageYears === 'number' && c.ageYears > 0) ? (c.ageYears + '-year-old ') : '';
  const heightCat = clean(c.body && c.body.heightCategory) || 'child';
  const build     = clean(c.body && c.body.build) || 'average';
  lines.push(`CHARACTER #${idx} — ${name} (${age}${heightCat}):`);
  lines.push(`  BODY:    ${build} ${heightCat} build`);
  if (c.hair) {
    const h = [clean(c.hair.color), clean(c.hair.style), clean(c.hair.length)].filter(has).join(', ');
    if (h) lines.push(`  HAIR:    ${h}`);
  }
  if (c.eyes && has(c.eyes.color)) lines.push(`  EYES:    ${clean(c.eyes.color)}`);
  if (c.skin && has(c.skin.tone))  lines.push(`  SKIN:    ${clean(c.skin.tone)}`);

  // OUTFIT — verbatim slots. Force fallback wenn LLM nichts geliefert hat.
  const o = c.outfit || {};
  let top         = clean(o.top);
  let bottom      = clean(o.bottom);
  let footwear    = clean(o.footwear);
  let accessories = clean(o.accessories) || 'none';
  if (!has(top))      top      = 'plain casual t-shirt in a neutral color';
  if (!has(bottom))   bottom   = 'plain casual trousers';
  if (!has(footwear)) footwear = 'simple closed shoes';
  lines.push(`  OUTFIT (identical in every scene — never alter):`);
  lines.push(`    TOP:         ${top}`);
  lines.push(`    BOTTOM:      ${bottom}`);
  lines.push(`    FOOTWEAR:    ${footwear}`);
  lines.push(`    ACCESSORIES: ${accessories}`);

  const dfArr = filterVisualOnlyDF(Array.isArray(c.distinguishingFeatures) ? c.distinguishingFeatures.filter(has) : []);
  if (dfArr.length > 0) lines.push(`  DISTINGUISHING: ${dfArr.join('; ')}`);
  return lines.join('\n');
}

function buildAnimalBlock(c, idx) {
  const lines = [];
  const name    = clean(c.name) || ('Animal #' + idx);
  const species = clean(c.species) || 'animal';
  lines.push(`CHARACTER #${idx} — ${name} (real ${species}, anatomically accurate animal — NOT a person, NOT a child, NOT in costume, no clothing):`);
  if (c.fur) {
    const f = [clean(c.fur.color), clean(c.fur.pattern)].filter(has).join(', ');
    if (f) lines.push(`  FUR/PLUMAGE: ${f}`);
  }
  if (c.eyes && has(c.eyes.color)) lines.push(`  EYES:        ${clean(c.eyes.color)}`);
  if (c.body && has(c.body.build)) lines.push(`  BODY:        ${clean(c.body.build)}`);
  const dfArr = filterVisualOnlyDF(Array.isArray(c.distinguishingFeatures) ? c.distinguishingFeatures.filter(has) : []);
  if (dfArr.length > 0) lines.push(`  DISTINGUISHING: ${dfArr.join('; ')}`);
  return lines.join('\n');
}

function buildCreatureBlock(c, idx) {
  const lines = [];
  const name    = clean(c.name) || ('Creature #' + idx);
  const species = clean(c.species) || 'fantasy creature';
  lines.push(`CHARACTER #${idx} — ${name} (fantasy ${species}, picture-book creature):`);
  if (c.body) {
    const b = [clean(c.body.heightCategory), clean(c.body.build)].filter(has).join(', ');
    if (b) lines.push(`  BODY:    ${b}`);
  }
  if (c.fur) {
    const f = [clean(c.fur.color), clean(c.fur.pattern)].filter(has).join(', ');
    if (f) lines.push(`  HIDE:    ${f}`);
  }
  if (c.eyes && has(c.eyes.color)) lines.push(`  EYES:    ${clean(c.eyes.color)}`);
  if (c.outfit && (has(c.outfit.top) || has(c.outfit.bottom))) {
    lines.push(`  OUTFIT:`);
    if (has(c.outfit.top))    lines.push(`    TOP:    ${clean(c.outfit.top)}`);
    if (has(c.outfit.bottom)) lines.push(`    BOTTOM: ${clean(c.outfit.bottom)}`);
  }
  const dfArr = filterVisualOnlyDF(Array.isArray(c.distinguishingFeatures) ? c.distinguishingFeatures.filter(has) : []);
  if (dfArr.length > 0) lines.push(`  DISTINGUISHING: ${dfArr.join('; ')}`);
  return lines.join('\n');
}

function buildObjectBlock(c, idx) {
  const name = clean(c.name) || ('Object #' + idx);
  const df   = Array.isArray(c.distinguishingFeatures) ? c.distinguishingFeatures.filter(has) : [];
  const detail = df.length > 0 ? df.join('; ') : 'inanimate object from the story';
  return `CHARACTER #${idx} — ${name} (inanimate object): ${detail}`;
}

function buildCharacterBlock(c, idx) {
  const t = (c && c.type || 'human').toString().toLowerCase();
  if (t === 'animal')   return buildAnimalBlock(c, idx);
  if (t === 'creature') return buildCreatureBlock(c, idx);
  if (t === 'object')   return buildObjectBlock(c, idx);
  return buildHumanBlock(c, idx);
}

function buildPropBlock(p, idx) {
  const lines = [];
  const name = clean(p.name) || ('Prop #' + idx);
  lines.push(`PROP #${idx} — ${name}:`);
  if (has(p.color))    lines.push(`  COLOR:    ${clean(p.color)}`);
  if (has(p.material)) lines.push(`  MATERIAL: ${clean(p.material)}`);
  if (has(p.size))     lines.push(`  SIZE:     ${clean(p.size)}`);
  if (has(p.shape))    lines.push(`  SHAPE:    ${clean(p.shape)}`);
  if (typeof p.count === 'number') lines.push(`  COUNT:    ${p.count}`);
  if (has(p.heldBy))   lines.push(`  HELD BY:  ${clean(p.heldBy)} (${clean(p.heldIn) || 'see story'})`);
  else if (has(p.heldIn) && clean(p.heldIn) !== 'none') lines.push(`  HELD IN:  ${clean(p.heldIn)}`);
  return lines.join('\n');
}

function buildSettingBlock(s) {
  if (!s) return '';
  if (typeof s === 'string') {
    return `SETTING ANCHOR (global atmosphere stays constant; micro-location varies per scene per 'Setting focus'):\n  ${clean(s)}`;
  }
  const lines = ["SETTING ANCHOR (global atmosphere stays constant; micro-location varies per scene per 'Setting focus'):"];
  if (has(s.location))       lines.push(`  LOCATION:        ${clean(s.location)}`);
  if (has(s.timeOfDay))      lines.push(`  TIME-OF-DAY:     ${clean(s.timeOfDay)}`);
  if (has(s.weather))        lines.push(`  WEATHER:         ${clean(s.weather)}`);
  if (has(s.lightDirection)) lines.push(`  LIGHT DIRECTION: ${clean(s.lightDirection)} (consistent shadow direction)`);
  return lines.join('\n');
}

const characterBlocks = storyElements.characters.map((c, i) => buildCharacterBlock(c, i + 1));
const propBlocks      = storyElements.props.map((p, i) => buildPropBlock(p, i + 1));
const settingBlock    = buildSettingBlock(storyElements.setting);

const visualLockSections = [];
if (characterBlocks.length > 0) visualLockSections.push(characterBlocks.join('\n\n'));
if (propBlocks.length > 0)      visualLockSections.push(propBlocks.join('\n\n'));
if (settingBlock)               visualLockSections.push(settingBlock);

const visualLock = visualLockSections.length > 0
  ? '=== VISUAL LOCK (REPEAT VERBATIM IN EVERY SCENE — NEVER ALTER) ===\n\n'
    + visualLockSections.join('\n\n')
    + '\n\n=== END VISUAL LOCK ==='
  : '';

// characterReference bleibt als String erhalten (downstream-Kompat) — jetzt = VISUAL LOCK
const characterReference = visualLock;

const sceneRules = storyElements.sceneRules.filter(r => typeof r === 'string' && r.length > 0);

const hasNonHumanCharacter = (storyElements.characters || []).some(c => {
  const t = (c.type || 'human').toString().toLowerCase();
  return t === 'animal' || t === 'creature';
});

return { json: { ...prev, storyElements, characterReference, visualLock, sceneRules, hasNonHumanCharacter } };

// Auswertung der Probe-Generierung mit gpt-image-2.
// Bei Erfolg: erste Szene erhält den Probe-b64 (wird wiederverwendet),
// Bei Misserfolg: alle Szenen werden mit Gemini-Fallback markiert.
const probeResp = $input.first()?.json || {};
const probeSuccess = !!(probeResp && probeResp.data && probeResp.data[0] && probeResp.data[0].b64_json);
const probeB64 = probeSuccess ? probeResp.data[0].b64_json : null;

const allItems = $('Szenen parsen').all().map(it => it.json);
if (allItems.length === 0) {
  return [];
}

if (probeSuccess) {
  return allItems.map((item, idx) => ({
    json: {
      ...item,
      useFallback: false,
      prefilledB64: idx === 0 ? probeB64 : null,
      probeOutcome: 'openai-success',
      imageModel: 'gpt-image-2'
    }
  }));
} else {
  return allItems.map(item => ({
    json: {
      ...item,
      useFallback: true,
      prefilledB64: null,
      probeOutcome: 'openai-blocked',
      imageModel: 'gemini-2.5-flash-image'
    }
  }));
}

// Parst die Gemini-multimodal-Response: extrahiert die base64-Bild-Daten aus
// candidates[0].content.parts[*].inlineData.data und setzt sie als \$json.data
// (kompatibel mit dem GitHub-Upload-Knoten der \$json.data direkt nutzt)
const inputJson = $input.first().json;
const parts = inputJson?.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find(p => p && p.inlineData && p.inlineData.data);
if (!imagePart) {
  throw new Error('Gemini-Response enthält kein Bild — candidates[0].content.parts hat kein inlineData');
}
const data = imagePart.inlineData.data;
return { json: { ...inputJson, data } };

// Löst den n8n-binary-File-Pointer auf und gibt das base64 + mimeType ins json
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const base64 = buffer.toString('base64');
const mimeType = $input.first().binary?.data?.mimeType || 'image/png';
return { json: { ...$input.first().json, styleRefBase64: base64, styleRefMimeType: mimeType } };
